#include <iostream>

class Counter {
private:
    int count;
public:
    Counter(int c = 0) : count(c) {}
    int getCount() const { return count; }

    Counter& operator++() {
        ++count;
        return *this;
    }
};

int main() {
    Counter c(5);
    std::cout << "Initial c: " << c.getCount() << std::endl;

    Counter& c_ref = ++c;
    std::cout << "After ++c (c): " << c.getCount() << std::endl;
    std::cout << "After ++c (c_ref): " << c_ref.getCount() << std::endl;

    c.count = 5; // Reset for this specific test
    std::cout << "Before chained ++ (c reset to 5): " << c.getCount() << std::endl;
    Counter c_chained = ++(++c);
    std::cout << "After chained ++ (c): " << c.getCount() << std::endl;
    std::cout << "After chained ++ (c_chained): " << c_chained.getCount() << std::endl;
    return 0;
}
